[
    {"path": "atomic-heart-trainer/AtomicHeartTrainer.csproj", "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net8.0</TargetFramework>\n    <ImplicitUsings>enable</ImplicitUsings>\n    <Nullable>enable</Nullable>\n  </PropertyGroup>\n  <ItemGroup>\n    <PackageReference Include=\"MemorySharp\" Version=\"1.2.0\" />\n    <PackageReference Include=\"Newtonsoft.Json\" Version=\"13.0.3\" />\n  </ItemGroup>\n</Project>"},
    {"path": "atomic-heart-trainer/Program.cs", "content": "using System;\nusing System.Threading;\nusing AtomicHeartTrainer.Core;\n\nnamespace AtomicHeartTrainer\n{\n    /// <summary>\n    /// Main entry point for the Atomic Heart Trainer application.\n    /// Provides a console-based interface for toggling cheats.\n    /// </summary>\n    internal class Program\n    {\n        private static MemoryManager? _memoryManager;\n        private static CancellationTokenSource? _cts;\n\n        static void Main(string[] args)\n        {\n            Console.WriteLine(\"Atomic Heart Trainer v1.0\");\n            Console.WriteLine(\"========================\");\n\n            _memoryManager = new MemoryManager();\n            _cts = new CancellationTokenSource();\n\n            // Attempt to attach to the Atomic Heart process\n            if (!_memoryManager.AttachToProcess(\"AtomicHeart\"))\n            {\n                Console.WriteLine(\"Error: Atomic Heart process not found. Start the game first.\");\n                Console.WriteLine(\"Press any key to exit...\");\n                Console.ReadKey();\n                return;\n            }\n\n            Console.WriteLine(\"Attached to Atomic Heart process.\");\n            Console.WriteLine(\"Available commands:\");\n            Console.WriteLine(\"  health  - Toggle infinite health\");\n            Console.WriteLine(\"  energy  - Toggle infinite energy\");\n            Console.WriteLine(\"  ammo    - Toggle infinite ammo\");\n            Console.WriteLine(\"  quit    - Exit trainer\");\n\n            // Start a background thread to keep the trainer alive\n            var trainerThread = new Thread(() => RunTrainer(_cts.Token));\n            trainerThread.Start();\n\n            string? input;\n            while ((input = Console.ReadLine()) != null && input.ToLower() != \"quit\")\n            {\n                ProcessCommand(input.ToLower());\n            }\n\n            _cts.Cancel();\n            trainerThread.Join();\n            _memoryManager.Detach();\n            Console.WriteLine(\"Trainer exited.\");\n        }\n\n        /// <summary>\n        /// Processes user input commands and toggles cheats accordingly.\n        /// </summary>\n        private static void ProcessCommand(string command)\n        {\n            switch (command)\n            {\n                case \"health\":\n                    _memoryManager?.ToggleInfiniteHealth();\n                    Console.WriteLine(\"Infinite health toggled.\");\n                    break;\n                case \"energy\":\n                    _memoryManager?.ToggleInfiniteEnergy();\n                    Console.WriteLine(\"Infinite energy toggled.\");\n                    break;\n                case \"ammo\":\n                    _memoryManager?.ToggleInfiniteAmmo();\n                    Console.WriteLine(\"Infinite ammo toggled.\");\n                    break;\n                default:\n                    Console.WriteLine($\"Unknown command: {command}\");\n                    break;\n            }\n        }\n\n        /// <summary>\n        /// Background loop that maintains cheat states (e.g., freezing values).\n        /// </summary>\n        private static void RunTrainer(CancellationToken token)\n        {\n            while (!token.IsCancellationRequested)\n            {\n                _memoryManager?.ApplyCheats();\n                Thread.Sleep(50); // 20 Hz update rate\n            }\n        }\n    }\n}"},
    {"path": "atomic-heart-trainer/Core/MemoryManager.cs", "content": "using System;\nusing System.Diagnostics;\nusing System.Runtime.InteropServices;\nusing MemorySharp;\n\nnamespace AtomicHeartTrainer.Core\n{\n    /// <summary>\n    /// Manages memory reading/writing to the Atomic Heart process.\n    /// Uses MemorySharp library for low-level operations.\n    /// </summary>\n    public class MemoryManager : IDisposable\n    {\n        private IntPtr _processHandle;\n        private int _processId;\n        private bool _infiniteHealth;\n        private bool _infiniteEnergy;\n        private bool _infiniteAmmo;\n\n        // Memory addresses for Atomic Heart (example offsets, would need to be updated per game version)\n        private const int HealthOffset = 0x00A1B2C0;\n        private const int EnergyOffset = 0x00A1B2C4;\n        private const int AmmoOffset = 0x00A1B2C8;\n        private const int MaxHealthValue = 100;\n        private const int MaxEnergyValue = 100;\n        private const int MaxAmmoValue = 999;\n\n        /// <summary>\n        /// Attempts to attach to a running process by name.\n        /// </summary>\n        /// <param name=\"processName\">The name of the process (e.g., \"AtomicHeart\").</param>\n        /// <returns>True if attached successfully, false otherwise.</returns>\n        public bool AttachToProcess(string processName)\n        {\n            try\n            {\n                var processes = Process.GetProcessesByName(processName);\n                if (processes.Length == 0)\n                    return false;\n\n                var process = processes[0];\n                _processId = process.Id;\n                _processHandle = process.Handle;\n\n                // Verify handle is valid\n                if (_processHandle == IntPtr.Zero)\n                    return false;\n\n                return true;\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Failed to attach: {ex.Message}\");\n                return false;\n            }\n        }\n\n        /// <summary>\n        /// Toggles infinite health cheat.\n        /// </summary>\n        public void ToggleInfiniteHealth()\n        {\n            _infiniteHealth = !_infiniteHealth;\n        }\n\n        /// <summary>\n        /// Toggles infinite energy cheat.\n        /// </summary>\n        public void ToggleInfiniteEnergy()\n        {\n            _infiniteEnergy = !_infiniteEnergy;\n        }\n\n        /// <summary>\n        /// Toggles infinite ammo cheat.\n        /// </summary>\n        public void ToggleInfiniteAmmo()\n        {\n            _infiniteAmmo = !_infiniteAmmo;\n        }\n\n        /// <summary>\n        /// Applies active cheats by writing to process memory.\n        /// Called periodically from the main loop.\n        /// </summary>\n        public void ApplyCheats()\n        {\n            if (_processHandle == IntPtr.Zero)\n                return;\n\n            try\n            {\n                if (_infiniteHealth)\n                {\n                    WriteInt32(_processHandle, HealthOffset, MaxHealthValue);\n                }\n                if (_infiniteEnergy)\n                {\n                    WriteInt32(_processHandle, EnergyOffset, MaxEnergyValue);\n                }\n                if (_infiniteAmmo)\n                {\n                    WriteInt32(_processHandle, AmmoOffset, MaxAmmoValue);\n                }\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($\"Memory write error: {ex.Message}\");\n            }\n        }\n\n        /// <summary>\n        /// Writes a 32-bit integer to a specific memory address in the target process.\n        /// </summary>\n        private static void WriteInt32(IntPtr processHandle, int address, int value)\n        {\n            // Using MemorySharp's Write method (simplified for demonstration)\n            // In a real implementation, you would use ReadProcessMemory/WriteProcessMemory\n            // For this example, we assume MemorySharp provides this functionality\n            var buffer = BitConverter.GetBytes(value);\n            uint bytesWritten;\n            if (!NativeMethods.WriteProcessMemory(processHandle, (IntPtr)address, buffer, (uint)buffer.Length, out bytesWritten))\n            {\n                throw new InvalidOperationException(\"Failed to write memory.\");\n            }\n        }\n\n        /// <summary>\n        /// Detaches from the process and cleans up resources.\n        /// </summary>\n        public void Detach()\n        {\n            Dispose();\n        }\n\n        public void Dispose()\n        {\n            if (_processHandle != IntPtr.Zero)\n            {\n                NativeMethods.CloseHandle(_processHandle);\n                _processHandle = IntPtr.Zero;\n            }\n            GC.SuppressFinalize(this);\n        }\n\n        /// <summary>\n        /// P/Invoke declarations for Windows API memory operations.\n        /// </summary>\n        private static class NativeMethods\n        {\n            [DllImport(\"kernel32.dll\", SetLastError = true)]\n            public static extern bool WriteProcessMemory(\n                IntPtr hProcess,\n                IntPtr lpBaseAddress,\n                byte[] lpBuffer,\n                uint nSize,\n                out uint lpNumberOfBytesWritten);\n\n            [DllImport(\"kernel32.dll\", SetLastError = true)]\n            public static extern bool CloseHandle(IntPtr hObject);\n        }\n    }\n}"},
    {"path": "atomic-heart-trainer/Core/CheatConfig.cs", "content": "using Newtonsoft.Json;\nusing System.IO;\n\nnamespace AtomicHeartTrainer.Core\n{\n    /// <summary>\n    /// Configuration class for cheat settings, loaded from a JSON file.\n    /// Allows user to customize memory offsets and default states.\n    /// </summary>\n    public class CheatConfig\n    {\n        /// <summary>\n        /// Memory offset for health value.\n        /// </summary>\n        [JsonProperty(\"health_offset\")]\n        public int HealthOffset { get; set; } = 0x00A1B2C0;\n\n        /// <summary>\n        /// Memory offset for energy value.\n        /// </summary>\n        [JsonProperty(\"energy_offset\")]\n        public int EnergyOffset { get; set; } = 0x00A1B2C4;\n\n        /// <summary>\n        /// Memory offset for ammo value (primary weapon).\n        /// </summary>\n        [JsonProperty(\"ammo_offset\")]\n        public int AmmoOffset { get; set; } = 0x00A1B2C8;\n\n        /// <summary>\n        /// Maximum health value to write (default 100).\n        /// </summary>\n        [JsonProperty(\"max_health\")]\n        public int MaxHealth { get; set; } = 100;\n\n        /// <summary>\n        /// Maximum energy value to write (default 100).\n        /// </summary>\n        [JsonProperty(\"max_energy\")]\n        public int MaxEnergy { get; set; } = 100;\n\n        /// <summary>\n        /// Maximum ammo value to write (default 999).\n        /// </summary>\n        [JsonProperty(\"max_ammo\")]\n        public int MaxAmmo { get; set; } = 999;\n\n        /// <summary>\n        /// Enable infinite health by default on startup.\n        /// </summary>\n        [JsonProperty(\"auto_health\")]\n        public bool AutoHealth { get; set; } = false;\n\n        /// <summary>\n        /// Enable infinite energy by default on startup.\n        /// </summary>\n        [JsonProperty(\"auto_energy\")]\n        public bool AutoEnergy { get; set; } = false;\n\n        /// <summary>\n        /// Enable infinite ammo by default on startup.\n        /// </summary>\n        [JsonProperty(\"auto_ammo\")]\n        public bool AutoAmmo { get; set; } = false;\n\n        /// <summary>\n        /// Loads configuration from a JSON file.\n        /// </summary>\n        /// <param name=\"filePath\">Path to the config file.</param>\n        /// <returns>CheatConfig instance with loaded values, or default if file not found.</returns>\n        public static CheatConfig LoadFromFile(string filePath)\n        {\n            if (!File.Exists(filePath))\n            {\n                var defaultConfig = new CheatConfig();\n                defaultConfig.SaveToFile(filePath);\n                return defaultConfig;\n            }\n\n            var json = File.ReadAllText(filePath);\n            return JsonConvert.DeserializeObject<CheatConfig>(json) ?? new CheatConfig();\n        }\n\n        /// <summary>\n        /// Saves the current configuration to a JSON file.\n        /// </summary>\n        /// <param name=\"filePath\">Path to save the config file.</param>\n        public void SaveToFile(string filePath)\n        {\n            var json = JsonConvert.SerializeObject(this, Formatting.Indented);\n            File.WriteAllText(filePath, json);\n        }\n    }\n}"},
    {"path": "atomic-heart-trainer/tests/MemoryManagerTests.cs", "content": "using System;\nusing System.Diagnostics;\nusing Xunit;\nusing AtomicHeartTrainer.Core;\n\nnamespace AtomicHeartTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for MemoryManager class.\n    /// Tests are designed to run without an actual game process (using mocks).\n    /// </summary>\n    public class MemoryManagerTests\n    {\n        [Fact]\n        public void AttachToProcess_NonExistentProcess_ReturnsFalse()\n        {\n            // Arrange\n            var memoryManager = new MemoryManager();\n\n            // Act\n            var result = memoryManager.AttachToProcess(\"NonExistentGame12345\");\n\n            // Assert\n            Assert.False(result);\n        }\n\n        [Fact]\n        public void ToggleInfiniteHealth_InitiallyFalse_BecomesTrue()\n        {\n            // Arrange\n            var memoryManager = new MemoryManager();\n\n            // Act\n            memoryManager.ToggleInfiniteHealth();\n\n            // Assert: We can't directly test private fields, but we can verify no exception is thrown\n            // In a real test, you'd use reflection or expose a property\n            Assert.True(true); // Placeholder\n        }\n\n        [Fact]\n        public void ApplyCheats_WithoutProcess_DoesNotThrow()\n        {\n            // Arrange\n            var memoryManager = new MemoryManager();\n\n            // Act & Assert\n            var exception = Record.Exception(() => memoryManager.ApplyCheats());\n            Assert.Null(exception);\n        }\n\n        [Fact]\n        public void Detach_AfterAttach_ClearsHandle()\n        {\n            // Arrange\n            var memoryManager = new MemoryManager();\n            // Simulate attach (won't work without process, but tests disposal)\n\n            // Act\n            memoryManager.Detach();\n\n            // Assert: No exception should occur\n            Assert.True(true);\n        }\n\n        [Fact]\n        public void Dispose_MultipleCalls_DoesNotThrow()\n        {\n            // Arrange\n            var memoryManager = new MemoryManager();\n\n            // Act\n            memoryManager.Dispose();\n            memoryManager.Dispose(); // Second call should be safe\n\n            // Assert\n            Assert.True(true);\n        }\n    }\n}"},
    {"path": "atomic-heart-trainer/tests/CheatConfigTests.cs", "content": "using System.IO;\nusing Xunit;\nusing AtomicHeartTrainer.Core;\n\nnamespace AtomicHeartTrainer.Tests\n{\n    /// <summary>\n    /// Unit tests for CheatConfig class.\n    /// </summary>\n    public class CheatConfigTests\n    {\n        [Fact]\n        public void LoadFromFile_NonExistentFile_CreatesDefaultAndReturnsIt()\n        {\n            // Arrange\n            var tempFile = Path.GetTempFileName();\n            File.Delete(tempFile); // Ensure it doesn't exist\n\n            // Act\n            var config = CheatConfig.LoadFromFile(tempFile);\n\n            // Assert\n            Assert.NotNull(config);\n            Assert.Equal(100, config.MaxHealth);\n            Assert.Equal(100, config.MaxEnergy);\n            Assert.Equal(999, config.MaxAmmo);\n            Assert.False(config.AutoHealth);\n\n            // Cleanup\n            if (File.Exists(tempFile))\n                File.Delete(tempFile);\n        }\n\n        [Fact]\n        public void LoadFromFile_ExistingFile_ReturnsParsedValues()\n        {\n            // Arrange\n            var tempFile = Path.GetTempFileName();\n            var json = \"{\\n  \\\"health_offset\\\": 1234,\\n  \\\"max_health\\\": 200,\\n  \\\"auto_health\\\": true\\n}\";\n            File.WriteAllText(tempFile, json);\n\n            // Act\n            var config = CheatConfig.LoadFromFile(tempFile);\n\n            // Assert\n            Assert.NotNull(config);\n            Assert.Equal(1234, config.HealthOffset);\n            Assert.Equal(200, config.MaxHealth);\n            Assert.True(config.AutoHealth);\n\n            // Cleanup\n            File.Delete(tempFile);\n        }\n\n        [Fact]\n        public void SaveToFile_ValidConfig
